const allItems = $input.all();
const results = [];

function cleanText(text) {
  if (!text) return '';
  return text
    .replace(/<[^>]+>/g, '')
    .replace(/&amp;/g, '&').replace(/&lt;/g, '<').replace(/&gt;/g, '>')
    .replace(/&quot;/g, '"').replace(/&#39;/g, "'").replace(/&nbsp;/g, ' ')
    .replace(/\s+/g, ' ').trim();
}

function parseRSS(xml) {
  const items = [];
  const oneDayAgo = new Date(Date.now() - 24 * 60 * 60 * 1000);
  const itemPattern = /<item[\s>]([\s\S]*?)<\/item>/g;
  let match;
  while ((match = itemPattern.exec(xml)) !== null) {
    const itemXml = match[1];
    const titleM = itemXml.match(/<title>(?:<!\[CDATA\[)?([\s\S]*?)(?:\]\]>)?<\/title>/);
    const title = cleanText(titleM?.[1] || '');
    if (!title) continue;
    const descM = itemXml.match(/<description>(?:<!\[CDATA\[)?([\s\S]*?)(?:\]\]>)?<\/description>/);
    const description = cleanText(descM?.[1] || '').substring(0, 280);
    const dateM = itemXml.match(/<pubDate>([\s\S]*?)<\/pubDate>/) ||
                  itemXml.match(/<dc:date>([\s\S]*?)<\/dc:date>/);
    const pubDate = (dateM?.[1] || '').trim();
    if (pubDate) {
      const d = new Date(pubDate);
      if (!isNaN(d) && d < oneDayAgo) continue;
    }
    items.push({ title, description });
    if (items.length >= 3) break;
  }
  return items;
}

for (const item of allItems) {
  const xml = typeof item.json.rssXml === 'string' ? item.json.rssXml : '';
  const country = item.json.country || 'Unbekannt';
  const name = item.json.name || 'Unbekannt';
  if (!xml || xml.length < 50) continue;
  const articles = parseRSS(xml);
  if (articles.length === 0) continue;
  results.push({ json: { country, name, articles } });
}

return results;

const allItems = $input.all();
const grouped = {};

for (const item of allItems) {
  const { country, name, articles } = item.json;
  if (!country || !articles?.length) continue;
  if (!grouped[country]) grouped[country] = { country, articles: [] };
  for (const article of articles) {
    grouped[country].articles.push({ source: name, ...article });
  }
}

return Object.values(grouped).map(g => {
  const list = g.articles
    .map((a, i) => `${i + 1}. [${a.source}] ${a.title}${a.description ? '\n   ' + a.description : ''}`)
    .join('\n\n');
  const prompt = `Du bist ein neutraler Nachrichtenredakteur.\nFasse die folgenden Nachrichten aus ${g.country} auf Deutsch zusammen (3-4 Sätze, sachlich, keine Wertung, alle Sprachen übersetzen).\n\nNachrichten:\n${list}`;
  return { json: { country: g.country, prompt } };
});

const summaries = $input.all();
const countries = $('Nach Land gruppieren').all();

const today = new Date().toLocaleDateString('de-DE', { weekday: 'long', year: 'numeric', month: 'long', day: 'numeric' });
const time = new Date().toLocaleTimeString('de-DE', { hour: '2-digit', minute: '2-digit' });

const header = `🌍 *Weltlage – ${today}*\n\n`;
const footer = `\n_Quellen: Direkte Landesmedien • Stand ${time} Uhr_`;

let currentChunk = header;
const chunks = [];
const MAX_LEN = 3800;

for (let i = 0; i < summaries.length; i++) {
  const country = countries[i]?.json?.country || '?';
  const content = summaries[i]?.json?.choices?.[0]?.message?.content || 'Keine Daten verfügbar.';
  const section = `*${country}*\n${content}\n\n───────────────────\n\n`;
  if ((currentChunk + section).length > MAX_LEN) {
    chunks.push(currentChunk.trim());
    currentChunk = section;
  } else {
    currentChunk += section;
  }
}

if (currentChunk.trim()) chunks.push(currentChunk.trim() + footer);

return chunks.map((chunk, i) => ({
  json: { message: chunks.length > 1 ? chunk + `\n_(Teil ${i + 1}/${chunks.length})_` : chunk }
}));
